const appointmentForm=document.querySelector(".appointment-form"),whatsappNumber="917972569072";appointmentForm?.addEventListener("submit",t=>{t.preventDefault();const e=appointmentForm.querySelector("#name").value.trim(),o=appointmentForm.querySelector("#phone").value.trim(),n=appointmentForm.querySelector("#appointment-date").value,i=appointmentForm.querySelector("#appointment-time").value,a=appointmentForm.querySelector("#message").value.trim(),p=["Hello Doctor, I want to book an appointment.","",`Name: ${e}`,`Phone: ${o}`,`Appointment Date: ${n}`,`Appointment Time: ${i}`,`Problem: ${a}`,""].join("\n"),r=`https://wa.me/${whatsappNumber}?text=${encodeURIComponent(p)}`;window.open(r,"_blank","noopener")});
